// hooks/useSecureStorage.js
import { useState, useCallback } from 'react';
import secureStorage from '../utils/secureStorage';

export const useSecureStorage = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const execute = useCallback(async (operation) => {
    setLoading(true);
    setError(null);
    try {
      const result = await operation();
      return result;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  const saveProfile = useCallback(
    (profile) => execute(() => secureStorage.saveUserProfile(profile)),
    [execute]
  );

  const getProfile = useCallback(
    () => execute(() => secureStorage.getUserProfile()),
    [execute]
  );

  const savePayment = useCallback(
    (paymentData) => execute(() => secureStorage.savePaymentInfo(paymentData)),
    [execute]
  );

  const getPayment = useCallback(
    () => execute(() => secureStorage.getPaymentInfo()),
    [execute]
  );

  const saveTokens = useCallback(
    (tokens) => execute(() => secureStorage.saveAuthTokens(tokens)),
    [execute]
  );

  const getToken = useCallback(
    () => execute(() => secureStorage.getAuthToken()),
    [execute]
  );

  const isAuthenticated = useCallback(
    () => execute(() => secureStorage.isAuthenticated()),
    [execute]
  );

  const logout = useCallback(
    () => execute(() => secureStorage.logout()),
    [execute]
  );

  const clearAll = useCallback(
    () => execute(() => secureStorage.fullClear()),
    [execute]
  );

  return {
    loading,
    error,
    saveProfile,
    getProfile,
    savePayment,
    getPayment,
    saveTokens,
    getToken,
    isAuthenticated,
    logout,
    clearAll,
  };
};

